import React from "react";

const Cover = () => {
    return (
        <div className="ui segments">
            <div className="ui segment grid-top top-cover"></div>
            <div className="ui center grid choices">
                <button className="ui cell inverted purple button">Front/Back-end Developer</button>
                <button className="ui cell inverted purple button">Software Engineer</button>
            </div>
            <div className="ui segment grid-bottom bottom-cover"></div>
        </div>
    )
};
export default Cover;
